#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, M; scanf("%lld %lld", &N, &M);
        if (N > M/2){
            printf("%lld %lld\n", N, N);
        } else {
            long long k = M / N; // k >= 2
            long long B = N * k;
            printf("%lld %lld\n", N, B);
        }
    }
    return 0;
}

