import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        if N > M//2:
            out_lines.append(f"{N} {N}")
        else:
            k = M // N  # k >= 2
            B = N * k
            out_lines.append(f"{N} {B}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

